def icon_html(svg: str, size: int = 16, class_name: str = "") -> str:
    """Wrap an SVG icon with a span for inline use in Streamlit markdown."""
    styled = svg.replace('width="16"', f'width="{size}"').replace('height="16"', f'height="{size}"')
    return f'<span class="icon-wrap {class_name}">{styled}</span>'


def icon_text(icon_svg: str, text: str, size: int = 16) -> str:
    """Combine icon and text into a single HTML span."""
    return f'{icon_html(icon_svg, size)} {text}'
